document.addEventListener("DOMContentLoaded",function(){const t=document.getElementById("birth-date"),e=document.getElementById("calculate-btn"),n=document.getElementById("results-area");var o=new Date;function d(){var e=new Date(t.value);if(!isNaN(e.getTime()))if(e>o)alert("Birth date cannot be in the future.");else{var d=o.getFullYear()-e.getFullYear(),a=o.getMonth()-e.getMonth(),l=o.getDate()-e.getDate();if(l<0)a--,l+=new Date(o.getFullYear(),o.getMonth(),0).getDate();a<0&&(d--,a+=12);var m=Math.floor((o-e)/864e5),r=Math.floor(m/7),g=24*m,c=60*g,u=12*d+a,y=Math.floor(m/7);document.getElementById("r-years").textContent=d,document.getElementById("r-months").textContent=a,document.getElementById("r-days").textContent=l,document.getElementById("r-hours").textContent=g.toLocaleString(),document.getElementById("r-minutes").textContent=c.toLocaleString(),document.getElementById("d-days").textContent=m.toLocaleString(),document.getElementById("d-weeks").textContent=r.toLocaleString(),document.getElementById("d-hours").textContent=g.toLocaleString(),document.getElementById("d-minutes").textContent=c.toLocaleString(),document.getElementById("d-dow").textContent=e.toLocaleDateString("en-US",{weekday:"long"}),document.getElementById("d-months-total").textContent=u.toLocaleString(),document.getElementById("d-weeks-total").textContent=y.toLocaleString();var i=new Date(o.getFullYear(),e.getMonth(),e.getDate());i<=o&&i.setFullYear(i.getFullYear()+1);var s=Math.ceil((i-o)/864e5);document.getElementById("d-next-bd").textContent=i.toLocaleDateString("en-US",{month:"long",day:"numeric",year:"numeric"});var E=document.getElementById("birthday-countdown");0===s?(document.getElementById("bd-days").textContent="0",document.getElementById("bd-message").textContent="Happy Birthday! Today is your birthday!"):(document.getElementById("bd-days").textContent=s,document.getElementById("bd-message").textContent="days until your next birthday"),E.style.display="block",n.style.display="block"}}t.max=o.toISOString().split("T")[0],e.addEventListener("click",d),t.addEventListener("change",d)});